import React from "react";
import { useTranslation } from "react-i18next";
import { Row, Col, Card, Typography, Tag, Progress, Space, Badge, theme, Tooltip, Empty, Flex } from "antd";
import {
   DesktopOutlined,
   RobotOutlined,
   ScanOutlined,
   GatewayOutlined,
   ThunderboltOutlined,
   CheckCircleOutlined,
   ExclamationCircleOutlined,
   ClockCircleOutlined,
   InfoCircleOutlined,
   AimOutlined,
   SettingOutlined
} from "@ant-design/icons";
import ReactECharts from "echarts-for-react";
import { QUARANTINE_DB } from "../../../mocks/db";

const { Title, Text } = Typography;

const DeviceStatusPage: React.FC = () => {
   const { t } = useTranslation(["quarantine", "monitoring", "dashboard", "scenario"]);
   const { token } = theme.useToken();

   // [DATA-CONSISTENCY] DB에서 장비 데이터 및 통계 추출
   const allDevices = QUARANTINE_DB.devices || [];
   const stats = React.useMemo(() => {
      return {
         total: allDevices.length,
         online: allDevices.filter(d => d.status === 'online').length,
         warning: allDevices.filter(d => d.status === 'warning').length,
         error: allDevices.filter(d => d.status === 'error').length,
      };
   }, [allDevices]);

   // 카테고리별 집계
   const categories = React.useMemo(() => {
      const counts: Record<string, { cur: number, tot: number, color: string }> = {
         Robot: { cur: 0, tot: 0, color: token.colorPrimary },
         Scanner: { cur: 0, tot: 0, color: token.colorSuccess },
         Tunnel: { cur: 0, tot: 0, color: token.colorInfo },
         Disinfector: { cur: 0, tot: 0, color: token.colorWarning },
      };

      allDevices.forEach(d => {
         if (counts[d.type]) {
            counts[d.type].tot += 1;
            if (d.status === 'online') counts[d.type].cur += 1;
         }
      });

      return Object.entries(counts).map(([key, val]) => ({
         type: key,
         name: t(`monitoring:categories.${key.toLowerCase()}`),
         ...val
      }));
   }, [allDevices, t, token]);

   const getDonutOption = (current: number, total: number, color: string) => ({
      series: [
         {
            type: 'pie',
            radius: ['65%', '85%'],
            avoidLabelOverlap: false,
            label: {
               show: true,
               position: 'center',
               formatter: `${Math.round((current / total) * 100)}%`,
               fontSize: 14,
               fontWeight: 'bold',
               color: token.colorText
            },
            data: [
               { value: current, itemStyle: { color: color } },
               { value: total - current, itemStyle: { color: 'rgba(255,255,255,0.05)' } }
            ],
            silent: true
         }
      ]
   });

   return (
      <div className="p-6 h-[calc(100vh-64px)] flex flex-col gap-6 overflow-hidden" style={{ background: token.colorBgLayout }}>
         {/* Header */}
         <div className="flex justify-between items-center bg-black/20 p-4 rounded-xl border border-white/5">
            <Flex align="center" gap={12}>
               <div className="w-10 h-10 rounded-lg flex items-center justify-center" style={{ background: `${token.colorPrimary}22` }}>
                  <DesktopOutlined style={{ color: token.colorPrimary, fontSize: 20 }} />
               </div>
               <div>
                  <Title level={4} style={{ margin: 0, color: token.colorText, fontWeight: "bold" }}>
                     {t("monitoring:deviceOprtn")}
                  </Title>
                  <Text style={{ color: token.colorTextQuaternary, fontSize: 12 }}>
                     Monitoring {stats.total} devices across Terminal 1
                  </Text>
               </div>
            </Flex>
            <Tag color="cyan" className="m-0 px-3 py-1 font-bold border-none" style={{ borderRadius: 6 }}>
               {t("monitoring:realtimeMonitoring")}
            </Tag>
         </div>

         <div className="flex-1 flex gap-6 min-h-0">

            {/* Left Panel: Statistics */}
            <div className="w-[320px] flex flex-col gap-6 overflow-y-auto pr-2 custom-scrollbar">
               <Card
                  title={<Text className="font-bold" style={{ color: token.colorTextSecondary }}>{t("monitoring:statusByCategory")}</Text>}
                  className="shadow-sm border-none"
                  style={{ background: token.colorBgElevated }}
                  styles={{ body: { padding: '16px' } }}
               >
                  <div className="flex flex-col gap-4">
                     {categories.map((item, idx) => (
                        <div key={idx} className="flex items-center gap-4 p-4 rounded-xl border border-white/5" style={{ background: 'rgba(255,255,255,0.02)' }}>
                           <div className="w-16 h-16 shrink-0">
                              <ReactECharts option={getDonutOption(item.cur, item.tot, item.color)} style={{ height: '100%', width: '100%' }} />
                           </div>
                           <div className="flex-1">
                              <Text className="block mb-1 font-bold" style={{ fontSize: 13 }}>{item.name}</Text>
                              <Flex justify="space-between" align="center">
                                 <Text style={{ color: token.colorTextDescription, fontSize: 12 }}>{item.cur} / {item.tot}</Text>
                                 <Badge status={item.cur === item.tot ? "success" : "warning"} />
                              </Flex>
                           </div>
                        </div>
                     ))}
                  </div>
               </Card>

               <Card
                  title={<Text className="font-bold" style={{ color: token.colorTextSecondary }}>{t("monitoring:deviceDataStatus")}</Text>}
                  className="flex-1 shadow-sm border-none"
                  style={{ background: token.colorBgElevated }}
                  styles={{ body: { padding: '0 16px' } }}
               >
                  {allDevices.map((d, i) => (
                     <div key={i} className="flex justify-between items-center py-4 border-b border-white/5 group hover:bg-white/[0.02] cursor-pointer px-2 transition-all">
                        <Flex vertical>
                           <Text className="font-bold" style={{ fontSize: 13 }}>{d.id}</Text>
                           <Text style={{ color: token.colorTextQuaternary, fontSize: 11 }}>{d.gate}</Text>
                        </Flex>
                        <Tag
                           color={
                              d.status === 'online' ? "success" :
                                 d.status === 'error' ? "error" :
                                    "warning"
                           }
                           className="m-0 font-bold px-2 py-0.5"
                           style={{
                              fontSize: 11,
                              borderRadius: 4,
                              border: 'none',
                              color: d.status === 'error' ? '#ff4d4f' : d.status === 'warning' ? '#faad14' : '#52c41a',
                              background: d.status === 'error' ? 'rgba(255, 77, 79, 0.15)' :
                                 d.status === 'warning' ? 'rgba(250, 173, 20, 0.15)' :
                                    'rgba(82, 196, 26, 0.15)'
                           }}
                        >
                           {t(`monitoring:statusLabels.${d.status}`)}
                        </Tag>
                     </div>
                  ))}
               </Card>
            </div>

            {/* Center: Real Map (Floor Plan) */}
            <div className="flex-1 flex flex-col gap-6">
               <Card
                  className="flex-1 shadow-2xl border-none relative overflow-hidden group"
                  style={{ background: '#0a0c14' }}
                  styles={{ body: { padding: 0 } }}
               >
                  {/* Floor Plan Layer */}
                  <div className="absolute inset-0 flex items-center justify-center p-12">
                     <div
                        className="w-full h-full rounded-2xl border-2 border-dashed border-white/5 flex items-center justify-center overflow-hidden"
                        style={{ background: 'linear-gradient(135deg, #0f121d 0%, #161a29 100%)' }}
                     >
                        {/* Placeholder for real CAD/SVG map */}
                        <img
                           src="https://placehold.co/1200x800/161a29/334155?text=DETAILED+TERMINAL+MAP"
                           alt="Floor Plan"
                           className="max-w-[100%] opacity-40 mix-blend-screen"
                        />

                        {/* [LIVE-MARKERS] DB 데이터를 기반으로 맵 위에 마커 배치 */}
                        <div className="absolute inset-0">
                           {allDevices.map((d, i) => (
                              <Tooltip
                                 key={i}
                                 title={
                                    <div className="p-2">
                                       <Text strong style={{ color: '#fff' }}>{d.name}</Text><br />
                                       <Text style={{ color: '#aaa', fontSize: 11 }}>Status: {d.status}</Text><br />
                                       <Text style={{ color: '#aaa', fontSize: 11 }}>Power: {d.metrics.batt}</Text>
                                    </div>
                                 }
                              >
                                 <div
                                    className="absolute cursor-pointer transition-all hover:scale-125"
                                    style={{
                                       left: `${(d.x / 1500) * 100}%`,
                                       top: `${(d.y / 800) * 100}%`,
                                       filter: d.status !== 'online' ? 'drop-shadow(0 0 10px rgba(255,77,79,0.5))' : 'none'
                                    }}
                                 >
                                    <div className="relative">
                                       {d.status === 'error' && <div className="absolute -inset-2 bg-red-500/20 rounded-full animate-ping" />}
                                       <div className={`w-8 h-8 rounded-full border-2 flex items-center justify-center shadow-lg bg-black/60`}
                                          style={{ borderColor: d.status === 'online' ? token.colorSuccess : d.status === 'error' ? token.colorError : token.colorWarning }}>
                                          {d.type === 'Robot' ? <RobotOutlined style={{ color: d.status === 'online' ? token.colorSuccess : d.status === 'error' ? token.colorError : token.colorWarning }} /> :
                                             d.type === 'Scanner' ? <ScanOutlined style={{ color: d.status === 'online' ? token.colorSuccess : d.status === 'error' ? token.colorError : token.colorWarning }} /> :
                                                <AimOutlined style={{ color: d.status === 'online' ? token.colorSuccess : d.status === 'error' ? token.colorError : token.colorWarning }} />}
                                       </div>
                                    </div>
                                 </div>
                              </Tooltip>
                           ))}
                        </div>
                     </div>
                  </div>

                  {/* Data Overlay (Status Summary) */}
                  <div className="absolute bottom-8 left-8 right-8 grid grid-cols-4 gap-6">
                     {[
                        { label: t("common:total"), val: stats.total, color: token.colorText, icon: <DesktopOutlined /> },
                        { label: t("monitoring:statusLabels.online"), val: stats.online, color: '#52c41a', icon: <CheckCircleOutlined /> },
                        { label: t("monitoring:statusLabels.warning"), val: stats.warning, color: '#faad14', icon: <SettingOutlined /> },
                        { label: t("monitoring:statusLabels.error"), val: stats.error, color: '#ff4d4f', icon: <ExclamationCircleOutlined /> }
                     ].map((s, i) => (
                        <div key={i} className="backdrop-blur-xl p-5 rounded-2xl border border-white/10 shadow-2xl" style={{ background: 'rgba(20,24,38,0.7)' }}>
                           <Flex align="center" gap={12} className="mb-2">
                              <div style={{ color: s.color, opacity: 0.7 }}>{s.icon}</div>
                              <Text style={{ fontSize: 13, color: token.colorTextDescription }}>{s.label}</Text>
                           </Flex>
                           <Text className="text-3xl font-bold font-mono" style={{ color: s.color }}>{s.val}</Text>
                        </div>
                     ))}
                  </div>
               </Card>
            </div>

            {/* Right Panel: History */}
            <div className="w-[320px] flex flex-col gap-6 overflow-y-auto pr-2 custom-scrollbar">
               <Card
                  title={<Text className="font-bold" style={{ color: token.colorTextSecondary }}>{t("monitoring:deviceOpHistory")}</Text>}
                  className="flex-1 shadow-sm border-none"
                  style={{ background: token.colorBgElevated }}
                  styles={{ body: { padding: '20px 16px' } }}
               >
                  <div className="flex flex-col">
                     {QUARANTINE_DB.history.map((item, idx) => (
                        <div key={idx} className="flex gap-4 items-start relative pb-8 last:pb-0">
                           {/* Timeline Line */}
                           <div className="absolute left-[7px] top-[18px] bottom-0 w-[1px] bg-white/5 last:hidden" />

                           <div className="relative z-10 shrink-0">
                              <div className="w-4 h-4 rounded-full border-2 bg-[#1a1c2e]"
                                 style={{ borderColor: item.status === 'success' ? token.colorSuccess : token.colorWarning }} />
                           </div>
                           <div className="flex-1 -mt-1">
                              <Flex justify="space-between" align="center" className="mb-1">
                                 <Text strong style={{ fontSize: 13, color: token.colorText }}>{item.target}</Text>
                                 <Text style={{ fontSize: 11, color: token.colorTextQuaternary }}>{item.time}</Text>
                              </Flex>
                              <Text style={{ color: token.colorTextSecondary, fontSize: 12, lineHeight: '1.5' }}>
                                 {t(`monitoring:events.${item.detail}`, { defaultValue: item.detail })}
                              </Text>
                           </div>
                        </div>
                     ))}
                  </div>
               </Card>

               <Card
                  title={<Text className="font-bold" style={{ color: token.colorTextSecondary }}>{t("monitoring:recentEvents")}</Text>}
                  className="shadow-sm border-none"
                  style={{ background: token.colorBgElevated }}
               >
                  <div className="flex flex-col gap-3">
                     {QUARANTINE_DB.recentEvents.slice(0, 2).map((ev, i) => (
                        <div key={i} className="flex items-center gap-4 p-4 rounded-xl border border-white/5 active-event-glow"
                           style={{
                              background: i === 0 ? 'rgba(255, 77, 79, 0.12)' : 'rgba(255, 255, 255, 0.03)',
                              borderColor: i === 0 ? 'rgba(255, 77, 79, 0.2)' : 'rgba(255, 255, 255, 0.05)'
                           }}>
                           <div className={`w-10 h-10 rounded-lg flex items-center justify-center shrink-0 ${i === 0 ? 'bg-red-500/20' : 'bg-white/5'}`}>
                              <InfoCircleOutlined style={{ color: i === 0 ? '#ff4d4f' : token.colorInfo, fontSize: 18 }} />
                           </div>
                           <div className="flex-1 flex flex-col gap-1 overflow-hidden">
                              <Text strong className="block text-[14px]" style={{ color: i === 0 ? '#ff4d4f' : token.colorTextSecondary }}>
                                 {t(`monitoring:events.${ev.content}`, { defaultValue: ev.content })}
                              </Text>
                              <Text style={{ color: token.colorTextQuaternary, fontSize: 11, fontWeight: 300 }}>
                                 {ev.time}
                              </Text>
                           </div>
                        </div>
                     ))}
                  </div>
               </Card>
            </div>
         </div>


         <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.1); border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: rgba(255,255,255,0.2); }
        .active-event-glow { position: relative; overflow: hidden; }
        .active-event-glow::after {
           content: '';
           position: absolute;
           top: 0; left: -100%; width: 100%; height: 100%;
           background: linear-gradient(90deg, transparent, rgba(255,255,255,0.05), transparent);
           animation: sweep 3s infinite;
        }
        @keyframes sweep { 100% { left: 100%; } }
      `}</style>
      </div>
   );
};

export default DeviceStatusPage;
